 94→function CommentThread({
 95→  comment,
 96→  postId,
 97→  isLoggedIn,
 98→  onReply,
 99→  onToggleReplies,
100→  expandedReplies,
101→  colors,
102→  depth,
103→}: CommentThreadProps) {
