105→  const repliesQuery = useQuery({
106→    queryKey: ['comment-replies', comment.id],
107→    queryFn: () => socialApi.getReplies(postId, comment.id),
108→    enabled: isExpanded,
109→  });
110→
111→  const replies = repliesQuery.data?.comments ?? [];
112→  const replyCount = comment.reply_count ?? 0;
113→  const userName = comment.users?.name || 'User';
114→
115→  const avatarSize = depth === 0 ? 28 : 24;
116→  const bodyPaddingLeft = depth === 0 ? 36 : 32;
117→  const repliesMarginLeft = depth === 0 ? 36 : 24;
118→
119→  return (
120→    <View>
121→      <View style={[styles.commentCard, {borderTopColor: colors.borderCard}]}>
122→        <View style={styles.commentHeader}>
123→          <Avatar
124→            uri={(comment.users as any)?.image_url}
125→            name={comment.users?.name}
126→            size={avatarSize}
127→          />
128→          <View style={styles.commentMeta}>
129→            <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
130→              {userName}
131→            </Text>
132→            <Text style={[styles.commentTime, {color: colors.textFaint}]}>
133→              {formatRelativeDate(comment.created_at)}
134→            </Text>
135→          </View>
136→        </View>
137→        <Text style={[styles.commentBody, {color: colors.textSecondary, paddingLeft: bodyPaddingLeft}]}>
138→          {comment.comment || ''}
139→        </Text>
140→        <View style={[styles.commentActions, {paddingLeft: bodyPaddingLeft}]}>
141→          {isLoggedIn && (
142→            <Pressable
143→              style={styles.actionButton}
144→              onPress={() => onReply(comment.id, userName)}>
145→              <ReplyIcon size={14} color={colors.textMuted} />
146→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
147→                Reply
148→              </Text>
149→            </Pressable>
150→          )}
151→          {replyCount > 0 && (
152→            <Pressable
153→              style={styles.actionButton}
154→              onPress={() => onToggleReplies(comment.id)}>
155→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
156→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
157→              </Text>
158→            </Pressable>
159→          )}
160→        </View>
161→      </View>
162→
163→      {isExpanded && (
164→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight, marginLeft: repliesMarginLeft}]}>
165→          {repliesQuery.isLoading ? (
166→            <View style={styles.repliesLoading}>
167→              <ActivityIndicator size="small" color={colors.loaderColor} />
168→            </View>
169→          ) : repliesQuery.isError ? (
170→            <Text style={[styles.repliesError, {color: colors.danger}]}>
171→              Failed to load replies.
172→            </Text>
173→          ) : (
174→            replies.map(reply => (
175→              <CommentThread
176→                key={reply.id}
177→                comment={reply}
178→                postId={postId}
179→                isLoggedIn={isLoggedIn}
180→                onReply={onReply}
181→                onToggleReplies={onToggleReplies}
182→                expandedReplies={expandedReplies}
183→                colors={colors}
184→                depth={depth + 1}
185→              />
186→            ))
187→          )}
188→        </View>
189→      )}
190→    </View>
191→  );
192→}
