197→  const {journalId} = route.params;
198→  const token = session?.access_token ?? '';
199→  const [commentInput, setCommentInput] = useState('');
200→  const [repostCaption, setRepostCaption] = useState('');
201→  const [showRepost, setShowRepost] = useState(false);
202→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
203→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
