423→
424→        {/* Content body */}
425→        <LexicalRenderer content={journal?.content} />
426→
427→        {/* Related posts */}
428→        <RelatedPosts journalId={journalId} />
429→
430→        {/* Divider */}
431→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
432→
433→        {/* Comments section */}
434→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
435→          Comments ({commentCount})
436→        </Text>
437→
438→        {commentsQuery.isLoading ? (
439→          <View style={styles.commentLoading}>
440→            <ActivityIndicator color={colors.loaderColor} />
441→          </View>
442→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
443→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
444→            No comments yet. Be the first!
445→          </Text>
446→        ) : (
447→          comments
448→            .filter(c => !c.parent_id)
449→            .map(comment => (
450→              <CommentThread
451→                key={comment.id}
452→                comment={comment}
453→                postId={journalId}
454→                isLoggedIn={!!token}
455→                onReply={handleReply}
456→                onToggleReplies={handleToggleReplies}
457→                expandedReplies={expandedReplies}
458→                colors={colors}
459→                depth={0}
460→              />
461→            ))
462→        )}
463→
464→        {/* Comment input */}
465→        {token ? (
466→          <View style={styles.commentInputRow}>
467→            {replyingTo && (
468→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
469→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
470→                  Replying to {replyingTo.userName}
471→                </Text>
472→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
473→                  <XIcon size={16} color={colors.textMuted} />
474→                </Pressable>
475→              </View>
476→            )}
477→            <TextInput
478→              ref={inputRef}
479→              value={commentInput}
480→              onChangeText={setCommentInput}
481→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
482→              placeholderTextColor={colors.textFaint}
483→              style={[
484→                styles.commentInput,
485→                {
486→                  backgroundColor: colors.bgSecondary,
487→                  borderColor: colors.borderCard,
488→                  color: colors.textPrimary,
489→                },
490→              ]}
491→              maxLength={200}
492→              multiline
493→            />
494→            <PrimaryButton
495→              label={addCommentMutation.isPending ? 'Posting...' : 'Post'}
496→              onPress={() => addCommentMutation.mutate()}
497→              disabled={commentInput.trim().length === 0 || addCommentMutation.isPending}
498→            />
499→          </View>
500→        ) : null}
501→
502→        <View style={styles.bottomSpacer} />
503→      </View>
504→    </ScrollView>
505→  );
506→}
